import{_ as e,c as a,o as i,a4 as r}from"./chunks/framework.CzsDe1xi.js";const k=JSON.parse('{"title":"kube-proxy 原理","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/kube-proxy/原理.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/kube-proxy/原理.md","lastUpdated":1704901837000}'),t={name:"doc/DevOps/Kubernetes/基础/kube-proxy/原理.md"},s=r('<h1 id="kube-proxy-原理" tabindex="-1">kube-proxy 原理 <a class="header-anchor" href="#kube-proxy-原理" aria-label="Permalink to &quot;kube-proxy 原理&quot;">​</a></h1><h2 id="工作模式" tabindex="-1">工作模式 <a class="header-anchor" href="#工作模式" aria-label="Permalink to &quot;工作模式&quot;">​</a></h2><p>目前 Kube-proxy 支持4中代理模式：</p><ul><li>userspace 用户空间</li><li>iptables</li><li>ipvs</li><li>kernelspace 内核空间 其中 kernelspace 专用于windows。</li></ul><h3 id="userspace-模式" tabindex="-1">Userspace 模式 <a class="header-anchor" href="#userspace-模式" aria-label="Permalink to &quot;Userspace 模式&quot;">​</a></h3><p>在这种模式下，kube-proxy通过观察Kubernetes中service和endpoint对象的变化，当有新的service创建时，所有节点的kube-proxy在node节点上随机选择一个端口，在iptables中追加一条把访问service的请求重定向到这个端口的记录，并开始监听这个端口的连接请求。</p><h4 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点&quot;">​</a></h4><p>请求数据需要到kube-proxy中，就是用户空间中，才能决定真正要转发的实际服务地址，性能会有损耗。并且在应用执行过程中，kube-proxy的可用性也会影响系统的稳定</p><h3 id="iptables-模式-目前kube-proxy默认的工作模式" tabindex="-1">iptables 模式（目前kube-proxy默认的工作模式） <a class="header-anchor" href="#iptables-模式-目前kube-proxy默认的工作模式" aria-label="Permalink to &quot;iptables 模式（目前kube-proxy默认的工作模式）&quot;">​</a></h3><p>在这种模式下，kube-proxy通过观察Kubernetes中service和endpoint对象的变化，当有servcie创建时，kube-proxy在iptables中追加新的规则。对于service的每一个endpoint，会在iptables中追加一条规则，设定动作为DNAT，将目的地址设置成真正提供服务的pod地址；再为servcie追加规则，设定动作为跳转到对应的endpoint的规则上，</p><p>默认情况下，kube-proxy随机选择一个后端的服务，可以通过iptables中的 -m recent 模块实现session affinity功能，通过 -m statistic 模块实现负载均衡时的权重功能</p><h4 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点&quot;">​</a></h4><p>在这种逻辑下，数据转发都在系统内核层面做，提升了性能，并且即便kube-proxy不工作了，已经创建好的服务还能正常工作。</p><h4 id="缺点-1" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-1" aria-label="Permalink to &quot;缺点&quot;">​</a></h4><p>但是在这种模式下，如果选中的第一个pod不能响应，请求就会失败，不能像userspace模式，请求失败后kube-proxy还能对其他endpoint进行重试。</p><p>这就要求我们的应用(pod)要提供readiness probes功能，来验证后端服务是否能正常提供服务，kube-proxy只会将readiness probes测试通过的pod写入到iptables规则中，以此来避免将请求转发到不正常的后端服务中。</p><h3 id="ipvs-模式" tabindex="-1">IPVS 模式 <a class="header-anchor" href="#ipvs-模式" aria-label="Permalink to &quot;IPVS 模式&quot;">​</a></h3><p>由于在iptables模式中，kube-proxy需要为每一个服务，每一个endpoint都生成相应的iptables规则，当服务规模很大时，性能也将显著下降，因此kubernetes在1.8引入了IPVS模式，1.9版本中变成beta，在1.11版本中成为GA。</p><p>在IPVS模式下，kube-proxy观察Kubernetes中service和endpoint对象的变化，通过调用netlink接口创建相应的IPVS规则，并周期性的对Kubernetes的service、endpoint和IPVS规则进行同步，当访问一个service时，IPVS负责选择一个真实的后端提供服务。</p><p>IPVS模式也是基于netfilter的hook功能(INPUT阶段)，这点和iptables模式是一样的，但是用的是内核工作空间的hash表作为存储的数据结构，在这种模式下，iptables可通过ipset来验证具体请求是否满足某条规则。在service变成时，只用更新ipset中的记录，不用改变iptables的规则链，因此可以保证iptables中的规则不会随着服务的增加变多，在超大规模服务集群的情况下提供一致的性能效果。</p><p>在对规则进行同步时的性能也要高于iptables（只用对特定的一个hash表进行更新，而不是像iptables模式下对整个规则表进行操作），所以能提供更高的网络流量。</p><h4 id="优点-1" tabindex="-1">优点 <a class="header-anchor" href="#优点-1" aria-label="Permalink to &quot;优点&quot;">​</a></h4><ul><li>采用HASH表结构存储规则，大数据量下查找快速</li><li>iptables规则不会随着服务的增多变多</li><li>提供更多的后端选择算法</li></ul><h2 id="监听资源对象变化" tabindex="-1">监听资源对象变化 <a class="header-anchor" href="#监听资源对象变化" aria-label="Permalink to &quot;监听资源对象变化&quot;">​</a></h2><ul><li>service</li><li>endpoint/endpointslices</li><li>node</li></ul><p>然后根据监听资源变化操作代理后端来为服务配置负载均衡</p>',26),p=[s];function o(l,n,b,u,c,d){return i(),a("div",null,p)}const x=e(t,[["render",o]]);export{k as __pageData,x as default};
